{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_fe384504ad814230a94c521da0d02abe.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

<!-- Toast notification -->
@if (_toastVisible)
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "")">
        @_toastMessage
    </div>
}

<!-- Revoke session confirmation dialog -->
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop" @onclick="() => _showRevokeConfirm = false"></div>
    <div class="confirm-dialog">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?
            This will sign out that device immediately.</p>
        <div class="d-flex gap-2 justify-content-end">
            <button class="btn btn-secondary btn-sm" @onclick="() => _showRevokeConfirm = false">Cancel</button>
            <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    // ── Navigation ──────────────────────────────────────────

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile",       "Profile",       "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security",      "Security",      "🔒"),
        new("appearance",    "Appearance",    "🎨"),
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ───────────────────────────────────────────────

    private bool _toastVisible;
    private bool _toastIsError;
    private string _toastMessage = "";
    private CancellationTokenSource? _toastCts;

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile state ───────────────────────────────────────

    private UserProfile? _savedProfile;
    private string _profileName = "";
    private string _profileEmail = "";
    private string _profileBio = "";
    private string _profileAvatarUrl = "";

    private void LoadProfileFields(UserProfile p)
    {
        _profileName = p.DisplayName;
        _profileEmail = p.Email;
        _profileBio = p.Bio;
        _profileAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_profileName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            LoadProfileFields(_savedProfile);
    }

    // ── Notifications state ─────────────────────────────────

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    private void ToggleChannelMute(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    // ── Security state ──────────────────────────────────────

    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = _newPassword = _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        }
        _showRevokeConfirm = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // ── Appearance state ────────────────────────────────────

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e1e",
        _ => "#ffffff"
    };

    private string PreviewColor => _theme switch
    {
        "Dark" => "#d4d4d4",
        _ => "#212529"
    };

    // ── Lifecycle ───────────────────────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        LoadProfileFields(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _emailNotifications = notif.EmailNotifications;
        _pushNotifications = notif.PushNotifications;
        _weeklyDigest = notif.WeeklyDigest;
        _allChannels = notif.MutedChannels.ToList();
        _mutedChannels = notif.MutedChannels.ToHashSet();

        // Security
        _securitySettings = securityTask.Result;

        // Appearance
        var appearance = appearanceTask.Result;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;

        _loading = false;
    }

    // ── Render fragments ────────────────────────────────────

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h3 class="section-title">Profile</h3>
        <div class="settings-card">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_profileAvatarUrl" alt="Avatar" />
                </div>
                <span class="text-muted small">@_profileAvatarUrl</span>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_profileName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_profileEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="3" @bind="_profileBio"></textarea>
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h3 class="section-title">Notifications</h3>
        <div class="settings-card">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)e.Value!" />
                </div>
            </div>

            <hr />

            <h6>Muted Channels</h6>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="ch-@ch"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleChannelMute(ch, (bool)e.Value!)" />
                        <label class="form-check-label" for="ch-@ch">#@ch</label>
                    </div>
                }
            </div>

            <div class="mt-3">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </div>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h3 class="section-title">Security</h3>

        <!-- Change Password -->
        <div class="settings-card">
            <div class="expandable-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                <strong>Change Password</strong>
                <span class="expand-icon">@(_changePasswordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_changePasswordExpanded)
            {
                <div class="expandable-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                    @if (_securitySettings?.LastPasswordChange is not null)
                    {
                        <div class="text-muted small mt-2">
                            Last changed: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="settings-card">
            <div class="toggle-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="small">
                        @if (_securitySettings?.TwoFactorEnabled == true)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@(_securitySettings?.TwoFactorEnabled ?? false)"
                           disabled />
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="settings-card">
            <h6>Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-sm mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_securitySettings?.Sessions is not null)
                        {
                            var isFirst = true;
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                var s = session;
                                var current = isFirst;
                                <tr>
                                    <td>
                                        @s.Device
                                        @if (current)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@s.Location</td>
                                    <td>@FormatLastActive(s.LastActive)</td>
                                    <td>
                                        @if (!current)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => RequestRevokeSession(s)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                                isFirst = false;
                            }
                        }
                    </tbody>
                </table>
            </div>
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <h3 class="section-title">Appearance</h3>
        <div class="settings-card">
            <!-- Theme -->
            <div class="mb-4">
                <label class="form-label fw-bold">Theme</label>
                <div class="d-flex gap-3">
                    @foreach (var t in new[] { "Light", "Dark", "System" })
                    {
                        var theme = t;
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <label class="form-label fw-bold">Font Size</label>
                <div class="d-flex gap-3">
                    @foreach (var fs in new[] { "Small", "Medium", "Large" })
                    {
                        var size = fs;
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="mb-4">
                <label class="form-label fw-bold">Language</label>
                <select class="form-select" style="max-width: 250px;"
                        @onchange="e => _language = e.Value!.ToString()!">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang" selected="@(_language == lang)">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="mb-4">
                <div class="toggle-row">
                    <div>
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            <hr />

            <!-- Live Preview -->
            <div class="mb-3">
                <label class="form-label fw-bold">Preview</label>
                <div class="live-preview" style="background: @PreviewBackground; color: @PreviewColor; font-size: @PreviewFontSize; padding: @(_compactMode ? "0.5rem" : "1rem");">
                    <h6 style="color: @PreviewColor; margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">Preview Title</h6>
                    <p style="margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">
                        This is how your content will look with the selected settings.
                        The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                        and compact mode is <strong>@(_compactMode ? "on" : "off")</strong>.
                    </p>
                    <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">
                        Sample Button
                    </button>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </div>
    };
}
