@page "/settings"
@rendermode InteractiveServer
@using sv_fe384504ad814230a94c521da0d02abe.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

<!-- Toast notification -->
@if (_toastVisible)
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "")">
        @_toastMessage
    </div>
}

<!-- Revoke session confirmation dialog -->
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop" @onclick="() => _showRevokeConfirm = false"></div>
    <div class="confirm-dialog">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?
            This will sign out that device immediately.</p>
        <div class="d-flex gap-2 justify-content-end">
            <button class="btn btn-secondary btn-sm" @onclick="() => _showRevokeConfirm = false">Cancel</button>
            <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    // ── Navigation ──────────────────────────────────────────

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile",       "Profile",       "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security",      "Security",      "🔒"),
        new("appearance",    "Appearance",    "🎨"),
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ───────────────────────────────────────────────

    private bool _toastVisible;
    private bool _toastIsError;
    private string _toastMessage = "";
    private CancellationTokenSource? _toastCts;

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile state ───────────────────────────────────────

    private UserProfile? _savedProfile;
    private string _profileName = "";
    private string _profileEmail = "";
    private string _profileBio = "";
    private string _profileAvatarUrl = "";

    private void LoadProfileFields(UserProfile p)
    {
        _profileName = p.DisplayName;
        _profileEmail = p.Email;
        _profileBio = p.Bio;
        _profileAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_profileName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            LoadProfileFields(_savedProfile);
    }

    // ── Notifications state ─────────────────────────────────

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    private void ToggleChannelMute(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    // ── Security state ──────────────────────────────────────

    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = _newPassword = _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        }
        _showRevokeConfirm = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // ── Appearance state ────────────────────────────────────

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e1e",
        _ => "#ffffff"
    };

    private string PreviewColor => _theme switch
    {
        "Dark" => "#d4d4d4",
        _ => "#212529"
    };

    // ── Lifecycle ───────────────────────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        LoadProfileFields(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _emailNotifications = notif.EmailNotifications;
        _pushNotifications = notif.PushNotifications;
