    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h3 class="section-title">Notifications</h3>
        <div class="settings-card">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)e.Value!" />
                </div>
            </div>

            <hr />

            <h6>Muted Channels</h6>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="ch-@ch"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleChannelMute(ch, (bool)e.Value!)" />
